#include <stdio.h>

#define MOD	1000000007

int power(int a, int b) {
	int p;

	if (b == 0)
		return 1;
	p = power(a, b / 2);
	p = (long long) p * p % MOD;
	if (b % 2 == 1)
		p = (long long) p * a % MOD;
	return p;
}

int inv(int x) {
	return power(x, MOD - 2);
}

int fact(int n, int is_inv) {
	return n == 0 ? 1
		: (long long) fact(n - 1, is_inv) * (is_inv ? inv(n) : n) % MOD;
}

int choose(int n, int k) {
	return (long long) ((long long) fact(n, 0) * fact(k, 1) % MOD)
		* fact(n - k, 1) % MOD;
}

int main() {
	int n, m, k;

	scanf("%d%d%d", &n, &m, &k);
	printf("%lld\n", n - 1 < 2 * k || m - 1 < 2 * k ? 0
			: (long long) choose(n - 1, 2 * k) * choose(m - 1, 2 * k) % MOD);
	return 0;
}

