macro_rules! input {
    ($next:expr) => {};
    ($next:expr, ) => {};

    ($next:expr, $var:ident : $t:tt $($r:tt)*) => {
        let $var = read_value!($next, $t);
        input!{$next $($r)*}
    };
}

macro_rules! read_value {
    ($next:expr, ( $($t:tt),* )) => {
        ( $(read_value!($next, $t)),* )
    };

    ($next:expr, [ $t:tt ; $len:expr ]) => {
        (0..$len).map(|_| read_value!($next, $t)).collect::<Vec<_>>()
    };

    ($next:expr, chars) => {
        read_value!($next, String).chars().collect::<Vec<char>>()
    };

    ($next:expr, bytes) => {
        read_value!($next, String).into_bytes()
    };

    ($next:expr, usize1) => {
        read_value!($next, usize) - 1
    };

    ($next:expr, $t:ty) => {
        $next().parse::<$t>().expect("Parse error")
    };
}

const MOD: i64 = 1000000007;

// assume a, b positive
fn gcd(a: i64, b: i64) -> (i64, i64, i64) {
    if b == 0 {
        (1, 0, a)
    }
    else {
        let (x, y, d) = gcd(b, a%b); // xb + y(a-qb) = d   where q = a/b
        (y, x-y*(a/b), d)
    }
}

fn factorial_mod(a: i64) -> i64 {
    if a == 0 {
        1
    }
    else {
        a * factorial_mod(a-1) % MOD
    }
}

fn binomial_mod(n: i64, k: i64) -> i64 {
    let a = factorial_mod(k);
    let b = factorial_mod(n-k);
    let (inv_a, _, _) = gcd(a, MOD);
    let (inv_b, _, _) = gcd(b, MOD);
    let result = factorial_mod(n) * inv_a % MOD * inv_b % MOD;
    if result < 0 { result + MOD } else { result }
}

fn main() {
    let stdin = std::io::stdin();
    let mut bytes = std::io::Read::bytes(std::io::BufReader::new(stdin.lock()));
    let mut next = move || -> String{
        bytes
            .by_ref()
            .map(|r|r.unwrap() as char)
            .skip_while(|c|c.is_whitespace())
            .take_while(|c|!c.is_whitespace())
            .collect()
    };
    input! {next,
        n: i64,
        m: i64,
        k: i64,
    }
    if 2*k > n-1 || 2*k > m-1 {
        println!("0");
    }
    else {
        println!("{}", binomial_mod(n-1,2*k)*binomial_mod(m-1,2*k) % MOD);
    }
}
